// ===== C·ª§M ƒê·ªòNG T·ª™ ‚Äî PH·∫¶N 1: T·ª™ V·ª∞NG =====
function speakEnglish(text){
  try{
    if(!window.speechSynthesis) return;
    window.speechSynthesis.cancel();
    const u=new SpeechSynthesisUtterance(text);
    u.lang='en-US';u.rate=0.9;
    window.speechSynthesis.speak(u);
  }catch(e){}
}
function pvCard(v,idx){
  const synHtml = v.syn ? `<div class="mt-1 text-xs" style="color:#9b5de5"><b>ƒê·ªìng nghƒ©a:</b> ${v.syn}</div>` : '';
  return `<div class="glass rounded-2xl p-4 mb-3 card-hover pv-card" data-search="${(v.en+' '+v.meaning).toLowerCase()}">
    <div class="flex items-start justify-between gap-2">
      <div>
        <span class="font-800 text-dark2" style="font-size:16px">${idx+1}. ${v.en}</span>
        <span class="text-xs" style="color:var(--accent)"> ${v.ipa}</span>
      </div>
      <button onclick="speakEnglish('${v.en.replace(/'/g,"\\'")}')" class="icon-toggle" style="width:34px;height:34px;flex:none" title="Ph√°t √¢m">üîä</button>
    </div>
    <div class="text-sm mt-1" style="color:#155724"><b>Nghƒ©a:</b> ${v.meaning}</div>
    ${synHtml}
    <div class="ex-card mt-2" style="font-size:13px"><i>${v.ex_en}</i><br><span style="color:var(--accent)">‚Üí ${v.ex_vi}</span></div>
  </div>`;
}
function buildPvVocabHtml(){
  return `
  <div class="glass rounded-2xl p-4 mb-4" style="border-left:4px solid var(--accent)">
    <div class="font-800 text-dark2 mb-2">üìñ PH·∫¶N 1 ‚Äî DANH S√ÅCH T·ª™ V·ª∞NG C·ª§M ƒê·ªòNG T·ª™ (${PV_VOCAB.length} c·ª•m)</div>
    <div class="text-sm text-soft">ƒê·∫ßy ƒë·ªß phi√™n √¢m, nghƒ©a, v√≠ d·ª• song ng·ªØ v√Ý t·ª´ ƒë·ªìng nghƒ©a (n·∫øu c√≥). B·∫•m üîä ƒë·ªÉ nghe ph√°t √¢m.</div>
  </div>
  <input id="pvSearchInput" oninput="filterPvVocab(this.value)" placeholder="üîç T√¨m t·ª´ ho·∫∑c nghƒ©a ti·∫øng Vi·ªát..." class="w-full p-3 rounded-2xl mb-4 surface" style="border:1px solid rgba(0,0,0,.08);outline:none">
  <div id="pvVocabList">${PV_VOCAB.map((v,i)=>pvCard(v,i)).join('')}</div>`;
}
function filterPvVocab(query){
  const q=(query||'').toLowerCase().trim();
  document.querySelectorAll('#pvVocabList .pv-card').forEach(el=>{
    el.style.display = el.getAttribute('data-search').includes(q) ? '' : 'none';
  });
}
const PV_VOCAB_HTML = buildPvVocabHtml();

// ===== C·ª§M ƒê·ªòNG T·ª™ ‚Äî PH·∫¶N 2: TR√í CH∆ÝI =====
function pvExplainFromVocab(v){
  const synHtml = v.syn ? `<div class="mb-2"><b class="text-dark2">üîÅ ƒê·ªìng nghƒ©a:</b> ${v.syn}</div>` : '';
  return `<div class="mb-2"><b class="text-dark2">üîä Phi√™n √¢m:</b> <span style="color:var(--accent)">${v.ipa}</span>
    <button onclick="speakEnglish('${v.en.replace(/'/g,"\\'")}')" class="icon-toggle" style="width:28px;height:28px;display:inline-flex;vertical-align:middle;margin-left:6px">üîä</button></div>
    <div class="mb-2"><b class="text-dark2">üìö Nghƒ©a:</b> ${v.meaning}</div>
    ${synHtml}
    <div class="mb-1"><b class="text-dark2">üí¨ V√≠ d·ª• song ng·ªØ:</b></div>
    <div class="ex-card mb-2"><i>${v.ex_en}</i><br><span style="color:var(--accent)">‚Üí ${v.ex_vi}</span></div>`;
}

// GAME 1: Cho nghƒ©a ti·∫øng Vi·ªát -> ch·ªçn ƒë√∫ng c·ª•m ƒë·ªông t·ª´ ti·∫øng Anh (MCQ)
function buildPvGame1(){
  const list = PV_VOCAB.map((v,i)=>{
    let pool = PV_VOCAB.filter((x,j)=>j!==i);
    pool = shuffleArr(pool).slice(0,3);
    let opts = shuffleArr([v, ...pool]);
    const ansIdx = opts.findIndex(o=>o.en===v.en);
    const lettered = opts.map((o,k)=>`${String.fromCharCode(65+k)}. ${o.en}`);
    const explain = `<div class="mb-2 p-3 rounded-xl font-700" style="background:#d4edda;color:#155724">‚úÖ ƒê√°p √°n ƒë√∫ng: ${String.fromCharCode(65+ansIdx)}. ${v.en}</div>`+pvExplainFromVocab(v);
    return {id:'pvg1_'+i, type:'fill', q:`C·ª•m ƒë·ªông t·ª´ n√Ýo c√≥ nghƒ©a l√Ý: "<b>${v.meaning}</b>" ?`, vi:'', opts:lettered, ans:ansIdx, explain_detail:explain};
  });
  return shuffleArr(list);
}

// GAME 2: Cho nghƒ©a ti·∫øng Vi·ªát -> g√µ ƒë√∫ng c·ª•m ƒë·ªông t·ª´ ti·∫øng Anh
function buildPvGame2(){
  const list = PV_VOCAB.map((v,i)=>{
    const accept = [v.en.toLowerCase()];
    const explain = `<div class="mb-2 p-3 rounded-xl font-700" style="background:#d4edda;color:#155724">‚úÖ ƒê√°p √°n ƒë√∫ng: ${v.en}</div>`+pvExplainFromVocab(v);
    return {id:'pvg2_'+i, type:'typing', q:`C·ª•m ƒë·ªông t·ª´ ti·∫øng Anh n√Ýo c√≥ nghƒ©a l√Ý:<br>"<b>${v.meaning}</b>" ?`, vi:'', answer:v.en, accept, explain_detail:explain};
  });
  return shuffleArr(list);
}
const PV_GAME1_QUESTIONS = buildPvGame1();
const PV_GAME2_QUESTIONS = buildPvGame2();
